parameters.jsCode:
const openaiData = $input.all()[0].json;
const scriptData = JSON.parse(openaiData.choices[0].message.content);
const prospectData = $('Extract Research Data').item.json.prospectData;

return {
  template: scriptData.template,
  script: scriptData.script,
  scenes: scriptData.scenes,
  prospectData
};

// Poll Kie.ai for video status up to 6 times (90 seconds total)
const taskId = $('Generate Video (Kie.ai)').item.json.task_id;
const maxAttempts = 6;
const delaySeconds = 15;

for (let attempt = 1; attempt <= maxAttempts; attempt++) {
  const response = await $httpRequest({
    method: 'GET',
    url: `https://api.kie.ai/v1/videos/${taskId}`,
    headers: {
      'Authorization': 'Bearer cb711f74a221be35a20df8e26e722e04'
    }
  });

  const data = JSON.parse(response);

  if (data.status === 'completed') {
    return {
      success: true,
      videoUrl: data.video_url,
      thumbnailUrl: data.thumbnail_url,
      taskId,
      attempts: attempt
    };
  }

  if (data.status === 'failed') {
    throw new Error('Video generation failed');
  }

  // Still processing, wait before next attempt
  if (attempt < maxAttempts) {
    await new Promise(resolve => setTimeout(resolve, delaySeconds * 1000));
  }
}

// Timeout - still processing after all attempts
return {
  success: true,
  videoUrl: null,
  message: 'Video generation queued - check email for delivery',
  taskId
};

// Return final response to frontend
const result = $input.all()[0].json;

return {
  success: true,
  videoUrl: result.videoUrl,
  thumbnailUrl: result.thumbnailUrl,
  message: result.videoUrl ? 'Video ready' : 'Video queued for processing'
};
